using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.UnitTests;/// <summary>/// Good case: Revoke an existing consent/// Expected: 200 OK/// </summary>public class ConsentServiceTests_RevokeConsent_WithValidId_ShouldRevoke : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {        "AuthService",        "ConsentService"    };    [SkippableFact]    public async Task RevokeConsent_WithValidId_ShouldRevoke()    {        await AuthenticateAsPatientAsync(ConsentClient);        // First, grant a consent        var grantRequest = new         {             patientDid = TestSeedData.PatientUserId.ToString(),             granteeDid = TestSeedData.DoctorUserId.ToString(),             scope = "read"         };        var grantResponse = await PostAsJsonWithRetryAsync(ConsentClient, ApiEndpoints.Consents.Grant, grantRequest);                if (grantResponse.StatusCode != HttpStatusCode.Created && grantResponse.StatusCode != HttpStatusCode.OK)            return; // Skip if grant fails        var grantJson = await ReadJsonResponseAsync(grantResponse);        if (!grantJson.TryGetProperty("data", out var dataElement))            return;        if (!dataElement.TryGetProperty("consentId", out var consentIdElement))            return;        var consentId = Guid.Parse(consentIdElement.GetString()!);        // Now revoke it        var revokeRequest = new { reason = "Patient revokes consent" };                var revokeResponse = await PostAsJsonWithRetryAsync(            ConsentClient,             ApiEndpoints.Consents.Revoke(consentId),             revokeRequest);        Assert.True(            revokeResponse.StatusCode == HttpStatusCode.OK ||             revokeResponse.StatusCode == HttpStatusCode.NoContent,            $"Expected 200 or 204, got {revokeResponse.StatusCode}");    }}